const express = require('express')
const app = express()
app.use(express.json()) // for parsing application/json
app.post('/uploadXml', (req, res) => {
  const xml = req.body;

  const parseString = require('xml2js').parseString;
  
  parseString(xml, function (err, result) {
    console.log(result);
  });
});
app.listen(3000)